});
if (!bot.entity || bot.health <= 0) {
  return '<UNSAFE>: Bot is not alive.';
}
const getNearestZombie = function () {
  return Object.values(bot.entities).filter(function (e) {
    return e.isValid && (e.name === 'zombie' || e.name === 'husk' || e.name === 'drowned' || e.name === 'zombie_villager') && bot.entity.position.distanceTo(e.position) < 16;
  }).sort(function (a, b) {
    return bot.entity.position.distanceTo(a.position) - bot.entity.position.distanceTo(b.position);
  })[0];
};
const firstTarget = getNearestZombie();
if (!firstTarget) {
  return '<NO TARGET>: No zombies nearby to kite.';
}
startBackgroundSkill(bot, 'kite_zombie_nearby', async function (token) {
  const movements = new Movements(bot);
  movements.canDig = false;
  bot.pathfinder.setMovements(movements);
  const startTime = Date.now();
  const pollMs = 100;
  const attackRange = 3.5;
  try {
    if (weapon) {
      if (!await waitUntilWorldActive(bot, token, pollMs)) return;
      await bot.equip(weapon, 'hand');
    }
    while (canContinueBotAction(bot, token) && (Date.now() - startTime < args.maxDurationMs)) {
      if (!await waitUntilWorldActive(bot, token, pollMs)) return;
      const target = getNearestZombie();
      if (!target) {
        bot.pathfinder.setGoal(null);
        if (!await waitForActiveMs(bot, token, 500, pollMs)) return;
        continue;
      }
      const dist = bot.entity.position.distanceTo(target.position);
      if (dist < attackRange) {
        await bot.lookAt(target.position.offset(0, target.height || 1, 0), true);
        bot.attack(target);
      }
      if (dist < args.preferredDistanceBlocks) {
        const avoidGoal = new goals.GoalInvert(new goals.GoalNear(target.position.x, target.position.y, target.position.z, args.preferredDistanceBlocks));
        bot.pathfinder.setGoal(avoidGoal);
      } else {
        bot.pathfinder.setGoal(null);
      }
      if (!await waitForActiveMs(bot, token, pollMs, pollMs)) return;
    }
  } finally {
    bot.pathfinder.setGoal(null);
    bot.clearControlStates();
  }
});
return '<STARTED>: Kiting nearby zombies moving toward ' + args.preferredDistanceBlocks + 'm distance.';

const normalize = (s) => String(s).toLowerCase().replace(/\s+/g, '_');
const targetMaterial = normalize(args.materialName);
const getMaterial = () => bot.inventory.items().find(item => 
  normalize(item.name).includes(targetMaterial) || 
  normalize(item.displayName).includes(targetMaterial)
);

if (!bot.entity || bot.health <= 0) {
  return '<UNSAFE>: Bot is dead or missing.';
}

const initialItem = getMaterial();
if (!initialItem) {
  return '<NO ITEM>: Could not find material ' + args.materialName + ' in inventory.';
}

startBackgroundSkill(bot, 'build_defensive_pillar', async function (token) {
  const pollMs = 50;
  const startY = Math.floor(bot.entity.position.y);
  const targetY = startY + args.height;
  let blocksPlaced = 0;

  try {
    while (canContinueBotAction(bot, token) && blocksPlaced < args.maxBlocks) {
      const currentY = Math.floor(bot.entity.position.y);
      if (currentY >= targetY) break;

      const material = getMaterial();
      if (!material) break;

      if (!await waitUntilWorldActive(bot, token, pollMs)) return;

      // Ensure we are holding the planks
      if (!bot.heldItem || normalize(bot.heldItem.name) !== normalize(material.name)) {
        await bot.equip(material, 'hand');
      }

      const referenceBlock = bot.blockAt(bot.entity.position.offset(0, -1, 0));
      if (!referenceBlock) break;

      // Check for block above head
      const above = bot.blockAt(bot.entity.position.offset(0, 2, 0));
      if (above && above.boundingBox !== 'empty') {
        // Path blocked above head
        break;
      }

      // Look straight down at the block our feet are on
      await bot.lookAt(referenceBlock.position.offset(0.5, 1, 0.5), true);

      // Jump
      bot.setControlState('jump', true);
      // Wait for peak of jump
      if (!await waitForActiveMs(bot, token, 350, pollMs)) return;
      bot.setControlState('jump', false);

      try {
        await bot.placeBlock(referenceBlock, new Vec3(0, 1, 0));
        blocksPlaced++;
      } catch (err) {
        // If we fail to place (e.g. falling too fast or blocked), wait and try again
        if (!await waitForActiveMs(bot, token, 200, pollMs)) return;
      }

      // Brief pause to stabilize
      if (!await waitForActiveMs(bot, token, 100, pollMs)) return;
    }
  } finally {
    bot.setControlState('jump', false);
    bot.clearControlStates();
  }
});

return '<STARTED>: Commencing pillar construction up to height ' + (Math.floor(bot.entity.position.y) + args.height) + '.';
